int string_length(char *s)
/*@ With l n
    Require
      0 <= n && n < INT_MAX &&
      (forall (k: Z), (0 <= k && k < n) => l[k] != 0) &&
      CharArray::full(s, n + 1, app(l, cons(0, nil)))
    Ensure
      __return == n &&
      CharArray::full(s, n + 1, app(l, cons(0, nil)))
*/
{
    int i = 0;

    /*@ Inv
          0 <= i && i <= n &&
          s == s@pre &&
          (forall (k: Z), (0 <= k && k < n) => l[k] != 0) &&
          CharArray::full(s, n + 1, app(l, cons(0, nil)))
    */
    while (1)
    {
        if (s[i] == 0) {
            break;
        }
        i++;
    }

    return i;
}

#include "../../verification_stdlib.h"
#include "../../verification_list.h"
#include "../../char_array_def.h"

void string_copy(char *src, char *dst)
/*@ With l d n
    Require
      0 <= n && n < INT_MAX &&
      (forall (k: Z), (0 <= k && k < n) => l[k] != 0) &&
      CharArray::full(src, n + 1, app(l, cons(0, nil))) *
      CharArray::full(dst, n + 1, d)
    Ensure
      CharArray::full(src, n + 1, app(l, cons(0, nil))) *
      CharArray::full(dst, n + 1, app(l, cons(0, nil)))
*/
{
    int i = 0;

    while (1) {
        if (src[i] == 0) {
            break;
        }
        dst[i] = src[i];
        i++;
    }
    dst[i] = 0;
}

#include "verification_list.h"
#include "verification_stdlib.h"
#include "char_array_def.h"

void chars_initialize(char *a, int n, char m)
/*@ Require 0 <= n && n < INT_MAX && CharArray::undef_full(a, n)
    Ensure CharArray::full(a, n, repeat_Z(m, n))
*/
{
  int i;
  /*@ Inv
      0 <= i && i <= n@pre &&
      CharArray::full(a@pre, i, repeat_Z(m@pre, i)) *
      CharArray::undef_seg(a@pre, i, n@pre)
  */
  for (i = 0; i < n; i++)
  {
    a[i] = m;
  }
}
